Here's the complete implementation of the requested functions using the `sqlgen` library:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        for (const auto& record : records) {
          auto insert_query = sqlgen::insert_into(table_name)(record);
          sqlgen::exec(conn, insert_query).value();
        }
        return sqlgen::result<void>{};
      })
      .value();
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const T& new_value) {
  sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        auto update_query = sqlgen::update(table_name)
                           .set(col_name, new_value)
                           .where("CID"_col == record_id || 
                                  "ScID"_col == record_id ||
                                  "MID"_col == record_id ||
                                  "SNo"_col == std::to_string(record_id));
        return sqlgen::exec(conn, update_query);
      })
      .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        // Determine the primary key column based on table name
        std::string pk_column;
        if (table_name == "Student") {
          pk_column = "SNo";
          auto delete_query = sqlgen::delete_from(table_name)
                             .where(sqlgen::column(pk_column) == record_id);
          return sqlgen::exec(conn, delete_query);
        } else {
          pk_column = (table_name == "Course") ? "CID" : 
                     (table_name == "Score") ? "ScID" : "MID";
          int id = std::stoi(record_id);
          auto delete_query = sqlgen::delete_from(table_name)
                             .where(sqlgen::column(pk_column) == id);
          return sqlgen::exec(conn, delete_query);
        }
      })
      .value();
}
```

This implementation provides:

1. `add_eas_records`: A template function that inserts multiple records into the specified table using sqlgen's insert functionality.

2. `modify_eas_records_by_id`: A template function that updates a specific column of a record identified by its primary key ID. It handles different table structures by checking the appropriate primary key column.

3. `delete_eas_records_by_id`: A function that deletes a record based on its primary key ID. It determines the correct primary key column based on the table name and handles both string and integer IDs appropriately.

The functions properly connect to the database, execute the required SQL operations, and handle the results using sqlgen's monadic error handling with `.and_then()` and `.value()`.

