#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    try {
        // Connect to SQLite database (this will create the file if it doesn't exist)
        auto db = sqlgen::sqlite::Connection("test_db.sqlite");

        // Drop the Product table if it exists and create a new one
        db.execute("DROP TABLE IF EXISTS Product");
        db.execute(R"(
            CREATE TABLE Product (
                product_id INTEGER PRIMARY KEY,
                name VARCHAR(100) NOT NULL,
                price FLOAT NOT NULL,
                category VARCHAR(50) NOT NULL,
                stock INTEGER NOT NULL DEFAULT 0
            )
        )");

        // Begin transaction for efficient batch insertion
        auto transaction = db.begin_transaction();

        // Prepare the insert statement
        auto insert_stmt = db.prepare<R"(INSERT INTO Product (product_id, name, price, category, stock) VALUES (?, ?, ?, ?, ?))", int, std::string, float, std::string, int>();

        // Insert all products
        for (const auto& product : products) {
            insert_stmt.bind(product.product_id.value, product.name, product.price, product.category, product.stock);
            insert_stmt.execute();
            insert_stmt.reset();
        }

        // Commit the transaction
        transaction.commit();

        return true;
    } catch (const std::exception& e) {
        // Any exception will cause the transaction to be automatically rolled back
        return false;
    }
}

}  // namespace batch_insert_products
