               group_by(col<"course_id", "t1">, col<"title", "t1">);

  auto create_view_op = create_as<CourseStats>(query) | if_not_exists;
  create_view_op(conn);

  auto results = sqlgen::read<std::vector<CourseStats>>(conn).value();
