#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  try {
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Start transaction
    db.execute("BEGIN TRANSACTION");

    // Check if sender has sufficient funds and deduct amount
    auto update_result = db.execute(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    // If no rows were affected, sender doesn't exist or has insufficient funds
    if (update_result.rows_affected() == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // Add amount to receiver's account
    auto insert_result = db.execute(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    // If no rows were affected, receiver doesn't exist
    if (insert_result.rows_affected() == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // Commit transaction
    db.execute("COMMIT");
    return true;
  } catch (const std::exception& e) {
    // Rollback on any exception
    try {
      auto db = sqlgen::sqlite::connect("test_db.sqlite");
      db.execute("ROLLBACK");
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
