    // Update shipped orders to delivered (simulated)
    auto shipped_query = order_mapper.update()
        .set(&Order::status, "delivered")
        .where(sqlgen::eq(&Order::status, "shipped"));

    total_rows_affected += shipped_query.execute();

    return total_rows_affected;
}

