std::vector<DepProj> right_join_departments_projects() {
  // Connect to the SQLite database
  sqlgen::Database db = sqlgen::sqlite::connect("test_db.sqlite");

  // Perform RIGHT JOIN between Department and Project tables
  // Since SQL doesn't directly support RIGHT JOIN, we simulate it by swapping the tables and using LEFT JOIN
