 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Connect to the SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Begin transaction for better performance
    auto transaction = conn.begin_transaction();

    // Perform upsert (insert or replace) for each item
    for (const auto& item : items) {
      sqlgen::sqlite::upsert(conn, "Inventory", item);
    }

    // Commit the transaction
    transaction.commit();

    // Verify upsert behavior by reading back the items
