#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Create User table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS User (
      user_id INTEGER PRIMARY KEY,
      username VARCHAR(50) NOT NULL UNIQUE,
      email VARCHAR(100) NOT NULL UNIQUE,
      join_date DATETIME NOT NULL,
      city VARCHAR(50)
    )
  )");

  // Create Friendship table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1 INTEGER,
      user_id2 INTEGER,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    )
  )");

  // Clear existing data
  db.execute("DELETE FROM Friendship");
  db.execute("DELETE FROM User");

  // Insert users
  for (const auto& user : users) {
    db.execute("INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, ?)",
               user.user_id.value(), user.username, user.email, user.join_date.to_string(), 
               user.city.has_value() ? user.city.value() : "");
  }

  // Insert friendships (ensuring symmetry)
  for (const auto& friendship : friendships) {
    db.execute("INSERT OR IGNORE INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)",
               friendship.user1_id, friendship.user2_id, friendship.friendship_date.to_string());
    db.execute("INSERT OR IGNORE INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)",
               friendship.user2_id, friendship.user1_id, friendship.friendship_date.to_string());
  }

  // Query 1: Find mutual friends using SELF-JOIN
  auto mutual_friends_result = db.query<R"(
    SELECT u1.username, u2.username, COUNT(f1.user_id2) as mutual_friends
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
    GROUP BY u1.user_id, u2.user_id
    HAVING COUNT(f1.user_id2) > 0
  )">();

  // Query 2: Find users with more than N friends (using subquery)
  auto popular_users_result = db.query<R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)
    )
    ORDER BY friend_count DESC
  )">();

  // Query 3: Find friend-of-friend relationships
  auto friend_of_friend_result = db.query<R"(
    SELECT DISTINCT u1.username, u2.username
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id != u2.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE (f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id)
           OR (f3.user_id1 = u2.user_id AND f3.user_id2 = u1.user_id)
      )
  )">();

  // Query 4: Count friends per user and identify most connected users
  auto friend_count_result = db.query<R"(
    SELECT u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
    LIMIT 5
  )">();

  // Query 5: Find users in the same city who are not yet friends
  auto recommendation_result = db.query<R"(
    SELECT u1.username, u2.username, u1.city
    FROM User u1
    INNER JOIN User u2 ON u1.city = u2.city
    WHERE u1.user_id < u2.user_id
      AND u1.city IS NOT NULL
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f 
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      )
  )">();

  // For this function, we'll return the friend-of-friend connections as FriendConnection objects
  std::vector<FriendConnection> connections;
  for (const auto& row : friend_of_friend_result) {
    connections.push_back({std::get<0>(row), std::get<1>(row)});
  }

  return connections;
}

}  // namespace analyze_social_network
```

