  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a temporary SQLite table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  // Create SQLite connection
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Create Product table
  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Product (
      product_id INTEGER PRIMARY KEY,
      name TEXT NOT NULL,
      price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL NOT NULL
    )
  )");

  // Clear existing data
  conn.execute("DELETE FROM Product");

  // Insert products
  for (const auto& product : products) {
    conn.execute(
      "INSERT INTO Product (product_id, name, price, quantity, discount_rate) VALUES (?, ?, ?, ?, ?)",
      product.product_id.value(), product.name, product.price, product.quantity, product.discount_rate
    );
  }

  // Perform mathematical operations analysis
  auto result = conn.query<MathAnalysis>(R"(
    SELECT 
      product_id,
      name,
      ABS(price) as abs_price,
      CEIL(price) as ceil_price,
      FLOOR(price) as floor_price,
      ROUND(price, 2) as rounded_price,
      EXP(discount_rate/100) as exp_discount,
      LN(price) as ln_price,
      LOG2(quantity) as log2_quantity,
      SIN(discount_rate) as sin_discount,
      COS(discount_rate) as cos_discount,
      TAN(discount_rate) as tan_discount,
      SQRT(quantity) as sqrt_quantity
    FROM Product
  )");

  return result;
}

}  // namespace mathematical_operations_analysis

