#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database
  sqlgen::SQLite db("test_db.sqlite");

  // Enable foreign key constraints
  db.execute("PRAGMA foreign_keys = ON;");

  // Create tables
  db.create_table<Parent>();
  db.create_table<Child>();

  // Insert a parent record
  Parent parent_record;
  parent_record.parent_id = 1;
  parent_record.name = "Parent1";
  db.insert(parent_record);

  // Insert child records
  Child child1, child2;
  child1.child_id = 1;
  child1.parent_id = 1;
  child1.note = "Child1";

  child2.child_id = 2;
  child2.parent_id = 1;
  child2.note = "Child2";

  db.insert(child1);
  db.insert(child2);

  // Verify children were inserted
  auto children_before = db.select<Child>().where(sqlgen::col<Child, decltype(Child::parent_id)>(&Child::parent_id) == 1).execute();
  if (children_before.size() != 2) {
    return false;
  }

  // Delete parent record
  db.remove<Parent>().where(sqlgen::col<Parent, decltype(Parent::parent_id)>(&Parent::parent_id) == 1).execute();

  // Check if child records were automatically deleted
  auto children_after = db.select<Child>().where(sqlgen::col<Child, decltype(Child::parent_id)>(&Child::parent_id) == 1).execute();

  // Return true if all child records were deleted (cascade delete worked)
  return children_after.empty();
}

}  // namespace cascade_delete_demo
