        .set(&Account::balance, 400.0)
        .where(sqlgen::eq(&Account::account_id, 3))
        .execute();

    // Verify changes persisted by querying the updated records
    auto updated_account1 = conn.select<Account>()
                               .where(sqlgen::eq(&Account::account_id, 1))
                               .execute()
                               .front();

    auto updated_account2 = conn.select<Account>()
