    if (updated_account1.balance != 1500.0 || updated_account1.status != "premium") {
      return false;
    }

    if (updated_account2.status != "active") {
      return false;
    }

    if (updated_account3.balance != 400.0) {
      return false;
    }

    return true;
  } catch (const std::exception& e) {
    return false;
  }
}

}  // namespace update_set_operations
