```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  sqlgen::Database db("test_db.sqlite");

  // Register tables
  db.registerTable<Supplier>("Supplier");
  db.registerTable<Product>("Product");

  // Perform FULL JOIN using UNION of LEFT JOIN and RIGHT JOIN
  // Since SQLite doesn't support FULL JOIN directly, we simulate it
  std::string query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION ALL
    SELECT s.name as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  auto result = db.execute(query);
  std::vector<SupProd> supProds;

  while (result.next()) {
    SupProd supProd;
    supProd.supplier_name = result.get<std::string>("supplier_name");

    auto product_name = result.get<std::optional<std::string>>("product_name");
    supProd.product_name = product_name;

    supProds.push_back(supProd);
  }

  return supProds;
}

}  // namespace full_join_suppliers_products
