  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Create SQLite database connection
  sqlgen::SqliteDB db("test_db.sqlite");

  // Create tables
  auto deptTable = db.template CreateTable<Department>("Department");
  auto empTable = db.template CreateTable<Employee>("Employee");

  // Insert data
  for (const auto& dept : depts) {
    deptTable.Insert(dept);
  }

  for (const auto& emp : emps) {
    empTable.Insert(emp);
  }

  JoinAnalysis analysis;

  // INNER JOIN: Get employees with assigned departments
  auto innerQuery = sqlgen::Select(
    deptTable.department_name,
    empTable.first_name,
    empTable.last_name,
    empTable.salary
  ).From(deptTable).InnerJoin(empTable).On(deptTable.department_id == empTable.department_id);

  auto innerResults = db.Execute(innerQuery);
  for (const auto& row : innerResults) {
    analysis.inner_join_results.push_back({
      std::get<0>(row),  // department_name
      std::get<1>(row),  // first_name
      std::get<2>(row),  // last_name
      std::get<3>(row)   // salary
    });
  }

  // LEFT JOIN: Include all employees (even without departments)
  auto leftQuery = sqlgen::Select(
    deptTable.department_name,
    empTable.first_name,
    empTable.last_name,
    empTable.salary
  ).From(empTable).LeftJoin(deptTable).On(empTable.department_id == deptTable.department_id);

  auto leftResults = db.Execute(leftQuery);
  for (const auto& row : leftResults) {
    analysis.left_join_results.push_back({
      std::get<0>(row),  // department_name
      std::get<1>(row),  // first_name
      std::get<2>(row),  // last_name
      std::get<3>(row)   // salary
    });
  }

  // RIGHT JOIN: Include all departments (even without employees)
  auto rightQuery = sqlgen::Select(
    deptTable.department_name,
    empTable.first_name,
    empTable.last_name,
    empTable.salary
  ).From(empTable).RightJoin(deptTable).On(empTable.department_id == deptTable.department_id);

  auto rightResults = db.Execute(rightQuery);
  for (const auto& row : rightResults) {
    analysis.right_join_results.push_back({
      std::get<0>(row),  // department_name
      std::get<1>(row),  // first_name
      std::get<2>(row),  // last_name
      std::get<3>(row)   // salary
    });
  }

  // FULL JOIN: Include all employees and departments
  auto fullQuery = sqlgen::Select(
    deptTable.department_name,
    empTable.first_name,
    empTable.last_name,
    empTable.salary
  ).From(empTable).FullJoin(deptTable).On(empTable.department_id == deptTable.department_id);

  auto fullResults = db.Execute(fullQuery);
  for (const auto& row : fullResults) {
    analysis.full_join_results.push_back({
      std::get<0>(row),  // department_name
      std::get<1>(row),  // first_name
      std::get<2>(row),  // last_name
      std::get<3>(row)   // salary
    });
  }

  return analysis;
}

}  // namespace analyze_department_employees

